-- VYCISTENIE TABULIEK pred znovaspustenim seedu
TRUNCATE TABLE Playlist_Song, Queue_Song, Playlist, Queue,
               Advertisment_Impression, Advertisment, Device, Song, "User", Role
RESTART IDENTITY CASCADE;

-- 1. ROLE
SELECT setval('role_id_seq', 4);

-- 2. USER
SELECT setval('"User_id_seq"', 2000);

-- 3. DEVICE
SELECT setval('device_id_seq', 3276);

-- 4. ADVERTISMENT
SELECT setval('advertisment_id_seq', 50);

-- 5. ADVERTISMENT_IMPRESSION
SELECT setval('advertisment_impression_id_seq', 8000);

-- 6. SONG
SELECT setval('song_id_seq', 3000);

-- 7. QUEUE
SELECT setval('queue_id_seq', 2000);

-- 8. QUEUE_SONG
SELECT setval('queue_song_id_seq', 9215);

-- 9. PLAYLIST
SELECT setval('playlist_id_seq', 2616);

-- 10. PLAYLIST_SONG
SELECT setval('playlist_song_id_seq', 23915);




--Summary
SELECT 'Role' AS tabulka, COUNT(*) AS pocet FROM Role
UNION ALL SELECT 'User', COUNT(*) FROM "User"
UNION ALL SELECT 'Device', COUNT(*) FROM Device
UNION ALL SELECT 'Advertisment', COUNT(*) FROM Advertisment
UNION ALL SELECT 'Advertisment_Impression', COUNT(*) FROM Advertisment_Impression
UNION ALL SELECT 'Song', COUNT(*) FROM Song
UNION ALL SELECT 'Queue', COUNT(*) FROM Queue
UNION ALL SELECT 'Queue_Song', COUNT(*) FROM Queue_Song
UNION ALL SELECT 'Playlist', COUNT(*) FROM Playlist
UNION ALL SELECT 'Playlist_Song', COUNT(*) FROM Playlist_Song
ORDER BY pocet DESC;

